// ═══════════════════════════════════════════
// INGEST MESSAGE v4
// Handles: deduplication, rate limiting, parsing
// ═══════════════════════════════════════════

const body = $input.first().json.body;

// Guard: only process if messages exist
if (!body?.entry?.[0]?.changes?.[0]?.value?.messages) return [];

const value   = body.entry[0].changes[0].value;
const msg     = value.messages[0];
const phone   = msg.from;  // This is the patient's WhatsApp number
const phoneId = value.metadata.phone_number_id;
const profile = value.contacts?.[0]?.profile?.name || 'Patient';
const msgType = msg.type;
const msgId   = msg.id;
const timestamp = msg.timestamp;

// ── Global state ──────────────────────────
const data = $getWorkflowStaticData('global');

// ── Deduplication ─────────────────────────
if (!data.processed) data.processed = {};

// Cleanup: remove entries older than 1 hour to prevent memory bloat
const oneHourAgo = Date.now() - 3600000;
const procKeys = Object.keys(data.processed);
if (procKeys.length > 500) {
  procKeys
    .filter(k => data.processed[k] < oneHourAgo)
    .forEach(k => delete data.processed[k]);
}

if (data.processed[msgId]) {
  return []; // exact duplicate — already processed
}
data.processed[msgId] = Date.now();

// ── Rate limiting ─────────────────────────
// 1 message per 1.5 seconds per user
if (!data.rateLimit) data.rateLimit = {};
const now = Date.now();
const lastMsg = data.rateLimit[phone] || 0;
if (now - lastMsg < 1500) {
  return []; // too fast — ignore
}
data.rateLimit[phone] = now;

// ── Parse message content ─────────────────
let userText = '';
let buttonId = null;
let rawInteractiveType = null;

switch (msgType) {
  case 'text':
    userText = msg.text.body.trim();
    break;

  case 'interactive': {
    rawInteractiveType = msg.interactive.type;
    if (rawInteractiveType === 'button_reply') {
      buttonId = msg.interactive.button_reply.id;
      userText = msg.interactive.button_reply.title;
    } else if (rawInteractiveType === 'list_reply') {
      buttonId = msg.interactive.list_reply.id;
      userText = msg.interactive.list_reply.title;
    }
    break;
  }

  case 'location':
    // Handle location sharing
    const loc = msg.location;
    userText = `LOCATION: lat=${loc.latitude}, lng=${loc.longitude}`;
    if (loc.name) userText += `, name=${loc.name}`;
    break;

  default:
    // Unsupported type — still pass through so AI can respond gracefully
    userText = `[${msgType} message received]`;
}

if (!userText) return [];

return [{ json: {
  phone,
  phoneId,
  profile,
  msgType,
  rawInteractiveType,
  userText,
  buttonId,
  msgId,
  timestamp
}}];

// ═══════════════════════════════════════════
// CONTEXT BUILDER v4.1
// Builds structured prompt for Gemini
// ═══════════════════════════════════════════

const ing = $('Ingest Message1').first().json;
const { phone, phoneId, profile, userText, buttonId, msgType, rawInteractiveType, msgId, timestamp } = ing;

// ── Session ────────────────────────────────
const sessionItems = $('Load Session1').all().map(i => i.json);
const session = (sessionItems.length > 0 && sessionItems[0].phone)
  ? sessionItems[0]
  : { booking_draft: {}, last_intent: 'none', message_count: 0 };

// ── Conversation history ───────────────────
const convItems = $('Load Convo1').all().map(i => i.json);
const history = convItems
  .filter(h => h && h.role && h.content)
  .slice(-12);

const histText = history.length
  ? history.map(h => {
      const role = h.role === 'assistant' ? 'LyncDoc' : 'Patient';
      return `${role}: ${h.content}`;
    }).join('\n')
  : '(no previous messages — new conversation)';

// ── Booking draft ──────────────────────────
let draft = '{}';
let draftObj = {};
try {
  const bd = session.booking_draft;
  draftObj = typeof bd === 'string'
    ? JSON.parse(bd)
    : (bd && typeof bd === 'object' ? bd : {});
  draft = Object.keys(draftObj).length ? JSON.stringify(draftObj, null, 2) : '{}';
} catch(_) {}

// ── Date/Time ─────────────────────────────
const now = new Date();
const today = now.toISOString().split('T')[0];
const time = now.toLocaleTimeString('en-IN', {
  hour: '2-digit', minute: '2-digit', hour12: true,
  timeZone: 'Asia/Kolkata'
});
const dayName = now.toLocaleDateString('en-IN', { weekday: 'long', timeZone: 'Asia/Kolkata' });

// ── Determine message context ──────────────
let messageContext = '';
if (buttonId) {
  if (buttonId.startsWith('doctor_')) {
    const doctorId = buttonId.replace('doctor_', '');
    messageContext = `DOCTOR SELECTED: ID=${doctorId} (doctor_id = "${doctorId}")`;
  } else if (buttonId.startsWith('slot_')) {
    const slotId = buttonId.replace('slot_', '');
    messageContext = `SLOT SELECTED: slot_id=${slotId} (use this exact value for slot_id in booking)`;
  } else if (buttonId.startsWith('cancel_')) {
    const ref = buttonId.replace('cancel_', '');
    messageContext = `CANCELLATION SELECTED: booking_ref=${ref}`;
  } else if (buttonId.startsWith('reschedule_')) {
    const ref = buttonId.replace('reschedule_', '');
    messageContext = `RESCHEDULE SELECTED: booking_ref=${ref}`;
  } else if (buttonId.startsWith('view_')) {
    const ref = buttonId.replace('view_', '');
    messageContext = `BOOKING VIEWED: booking_ref=${ref} — show details and action buttons`;
  } else {
    messageContext = `BUTTON TAPPED: id=${buttonId}`;
  }
}

// ── Detect what was just asked ─────────────
// Find the last LyncDoc message to know what question was just asked
const lastAIMsg = history
  .filter(h => h.role === 'assistant')
  .slice(-1)[0];

let lastQuestion = '';
if (lastAIMsg && !buttonId) {
  const m = lastAIMsg.content.toLowerCase();
  if (m.includes('full name') || m.includes('patient\'s name') || m.includes('what is the name')) {
    lastQuestion = 'patient_name';
  } else if (m.includes('how old') || m.includes('age of') || m.includes('patient\'s age') || m.includes('old is')) {
    lastQuestion = 'patient_age';
  } else if (m.includes('gender') || m.includes('male') || m.includes('female')) {
    lastQuestion = 'patient_gender';
  } else if (m.includes('symptom') || m.includes('reason for visit') || m.includes('complaints')) {
    lastQuestion = 'symptoms';
  } else if (m.includes('pincode') || m.includes('pin code') || m.includes('6-digit')) {
    lastQuestion = 'pincode';
  }
}

// ── Determine next missing field ───────────
const missingFields = [];
if (!draftObj.patient_name) missingFields.push('patient_name');
if (!draftObj.patient_age)  missingFields.push('patient_age');
if (!draftObj.patient_gender) missingFields.push('patient_gender');
if (draftObj.symptoms === undefined) missingFields.push('symptoms');

const nextMissingField = missingFields[0] || null;

// ── Build answer context ───────────────────
let answerContext = '';
if (lastQuestion && msgType === 'text' && !buttonId) {
  answerContext = `ANSWER CONTEXT: Patient just answered "${userText}" in response to the question about ${lastQuestion}. Save "${userText}" as ${lastQuestion} in draft_update and immediately proceed to the next step.`;
}

// ── Build prompt ───────────────────────────
const promptLines = [
  '═══ PATIENT CONTEXT ═══',
  `PHONE: ${phone}`,
  `NAME: ${profile}`,
  `DATE: ${today} (${dayName}) | TIME: ${time} IST`,
  `LAST INTENT: ${session.last_intent || 'none'}`,
  `MESSAGE COUNT: ${session.message_count || 0}`,
  `MESSAGE TYPE: ${msgType}${rawInteractiveType ? ' / ' + rawInteractiveType : ''}`,
  '',
  '═══ BOOKING DRAFT (DO NOT ASK AGAIN) ═══',
  draft,
  '',
  nextMissingField ? `NEXT MISSING FIELD: ${nextMissingField}` : 'ALL PATIENT FIELDS COLLECTED',
  '',
  '═══ CONVERSATION HISTORY ═══',
  histText,
  '',
  '═══ CURRENT MESSAGE ═══',
  `Patient says: "${userText}"`,
  messageContext ? messageContext : '',
  answerContext ? answerContext : ''
].filter(Boolean);

const prompt = promptLines.join('\n');

return [{ json: { phone, phoneId, profile, userText, buttonId, msgType, draftObj, prompt } }];

// ═══════════════════════════════════════════
// RESPONSE PARSER v4
// Parses AI output with truncation recovery
// ═══════════════════════════════════════════

const raw      = $input.first().json.output || '';
const phone    = $('Context1').first().json.phone;
const phoneId  = $('Context1').first().json.phoneId;
const profile  = $('Context1').first().json.profile;
const userText = $('Context1').first().json.userText;
const msgType  = $('Context1').first().json.msgType;
const draftObj = $('Context1').first().json.draftObj || {};

let ai = null;

// ── Attempt 1: Clean and parse full JSON ──
try {
  let clean = raw
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/g, '')
    .trim();

  const s = clean.indexOf('{');
  const e = clean.lastIndexOf('}');

  if (s !== -1 && e !== -1 && e > s) {
    ai = JSON.parse(clean.slice(s, e + 1));
  }
} catch (_) {

  // ── Attempt 2: Truncation recovery ────────
  try {
    let clean = raw
      .replace(/```json\s*/gi, '')
      .replace(/```\s*/g, '')
      .trim();

    const s = clean.indexOf('{');
    if (s !== -1) {
      let partial = clean.slice(s);
      let depth = 0;
      let lastValidClose = -1;

      for (let i = 0; i < partial.length; i++) {
        if (partial[i] === '{') depth++;
        if (partial[i] === '}') {
          depth--;
          if (depth === 0) lastValidClose = i;
        }
      }

      if (lastValidClose > 0) {
        // Parse up to last valid closing brace
        ai = JSON.parse(partial.slice(0, lastValidClose + 1));
      } else {
        // Severely truncated — extract message field only
        const msgMatch = partial.match(/"message"\s*:\s*"((?:[^"\\]|\\.)*)"/);
        const intentMatch = partial.match(/"intent"\s*:\s*"([^"]+)"/);
        if (msgMatch) {
          ai = {
            message: msgMatch[1].replace(/\\n/g, '\n').replace(/\\t/g, ' '),
            component: 'text',
            intent: intentMatch ? intentMatch[1] : 'unknown',
            draft_update: null
          };
        }
      }
    }
  } catch (_2) {
    // Both attempts failed — will use fallback
  }
}

// ── Validate message field ─────────────────
if (ai && (!ai.message || typeof ai.message !== 'string' || ai.message.trim() === '')) {
  ai = null;
}

// ── Sanitize and enforce limits ────────────
if (ai) {
  // Truncate message
  ai.message = String(ai.message).slice(0, 1024);

  // Validate component
  const validComponents = ['text', 'buttons', 'list'];
  if (!validComponents.includes(ai.component)) {
    ai.component = 'text';
  }

  // Validate buttons
  if (ai.component === 'buttons') {
    if (!Array.isArray(ai.buttons) || ai.buttons.length === 0) {
      ai.component = 'text';
    } else {
      ai.buttons = ai.buttons.slice(0, 3).map(b => ({
        id: String(b.id || 'btn').slice(0, 256),
        title: String(b.title || '').slice(0, 20)
      }));
    }
  }

  // Validate list sections
  if (ai.component === 'list') {
    if (!Array.isArray(ai.list_sections) || ai.list_sections.length === 0) {
      ai.component = 'text';
    } else {
      ai.list_sections = ai.list_sections
        .map(sec => ({
          title: String(sec.title || '').slice(0, 24),
          rows: (sec.rows || [])
            .filter(r => r && r.id && r.title)
            .slice(0, 10)
            .map(r => ({
              id: String(r.id).slice(0, 200),
              title: String(r.title).slice(0, 24),
              ...(r.description ? { description: String(r.description).slice(0, 72) } : {})
            }))
        }))
        .filter(sec => sec.rows.length > 0); // remove empty sections

      if (ai.list_sections.length === 0) {
        ai.component = 'text'; // nothing left after filtering
      }
    }
  }

  // Validate intent
  const validIntents = ['book','reschedule','cancel','my_bookings','greeting','emergency','support','unknown','booking_confirmed','cancel_confirmed'];
  if (!validIntents.includes(ai.intent)) {
    ai.intent = 'unknown';
  }

  // Validate draft_update
  if (ai.draft_update !== null && typeof ai.draft_update !== 'object') {
    ai.draft_update = null;
  }
}

// ── Hard fallback ──────────────────────────
if (!ai) {
  ai = {
    message: '👋 Hi! Welcome to *LyncDoc*.\n\nHow can I help you today?',
    component: 'buttons',
    buttons: [
      { id: 'btn_book',     title: 'Book Appointment' },
      { id: 'btn_bookings', title: 'My Bookings' },
      { id: 'btn_human',    title: 'Talk to Human' }
    ],
    intent: 'unknown',
    draft_update: null
  };
}

return [{ json: { phone, phoneId, profile, userText, msgType, ai } }];

// ═══════════════════════════════════════════
// SESSION PAYLOAD v4.1
// Merges draft, handles intent-based clearing
// ═══════════════════════════════════════════

const phone   = $('Ingest Message1').first().json.phone;
const profile = $('Ingest Message1').first().json.profile;
const ai      = $('Response1').first().json.ai;

// ── Load existing session ──────────────────
const sessionItems = $('Load Session1').all().map(i => i.json);
const existing = (sessionItems.length > 0 && sessionItems[0].phone)
  ? sessionItems[0]
  : { booking_draft: {}, message_count: 0 };

// ── Parse existing draft safely ────────────
let existingDraft = {};
try {
  const bd = existing.booking_draft;
  existingDraft = typeof bd === 'string'
    ? JSON.parse(bd)
    : (bd && typeof bd === 'object' ? bd : {});
} catch(_) {}

// ── Merge draft update from AI ─────────────
let newDraft = existingDraft;
if (ai.draft_update && typeof ai.draft_update === 'object' && !Array.isArray(ai.draft_update)) {
  newDraft = { ...existingDraft, ...ai.draft_update };
  // Remove null/undefined values from draft
  Object.keys(newDraft).forEach(k => {
    if (newDraft[k] === null || newDraft[k] === undefined) {
      delete newDraft[k];
    }
  });
}

// ── Clear draft on terminal intents ────────
const clearIntents = ['booking_confirmed', 'cancel_confirmed', 'greeting'];
if (clearIntents.includes(ai.intent)) {
  newDraft = {};
}

// ── Also clear if booking ref just created ─
// Catches cases where Gemini returns intent=book instead of booking_confirmed
const aiMessage = ai.message || '';
const bookingJustCreated = 
  aiMessage.includes('LYN') && 
  (
    aiMessage.toLowerCase().includes('confirmed') ||
    aiMessage.toLowerCase().includes('reference') ||
    aiMessage.toLowerCase().includes('booking ref') ||
    aiMessage.toLowerCase().includes('see you on')
  );

if (bookingJustCreated) {
  newDraft = {};
}

// ── Also clear on greeting keywords ────────
// Catches "hi", "hello" etc. at any point in conversation
const userText = $('Ingest Message1').first().json.userText || '';
const greetingKeywords = ['hi', 'hello', 'hey', 'start', 'menu', 'restart', 'hii', 'helo'];
const isGreeting = greetingKeywords.includes(userText.toLowerCase().trim());

if (isGreeting) {
  newDraft = {};
}

// ── Build session upsert ───────────────────
const sessionUpsert = {
  phone,
  profile_name:  profile,
  booking_draft: newDraft,
  last_intent:   ai.intent || 'unknown',
  last_active:   new Date().toISOString(),
  message_count: (existing.message_count || 0) + 1
};

return [{ json: { phone, sessionUpsert, ai } }];

// ═══════════════════════════════════════════
// RENDER FORMAT TO WHATSAPP v4
// Converts AI response to WhatsApp payload
// ═══════════════════════════════════════════

const { phone, phoneId, ai } = $('Response1').first().json;

// ── Hard fallback ──────────────────────────
if (!ai?.message) {
  return [{ json: { phoneId, payload: {
    messaging_product: 'whatsapp',
    to: phone,
    type: 'text',
    text: { body: '⚠️ Something went wrong. Send *hi* to restart.' }
  }}}];
}

const msg  = String(ai.message).slice(0, 1024);
const comp = ai.component || 'text';
let payload;

// ── Buttons ────────────────────────────────
if (comp === 'buttons' && Array.isArray(ai.buttons) && ai.buttons.length > 0) {
  const buttons = ai.buttons
    .slice(0, 3)
    .filter(b => b && b.id && b.title)
    .map(b => ({
      type: 'reply',
      reply: {
        id:    String(b.id).slice(0, 256),
        title: String(b.title).slice(0, 20)
      }
    }));

  if (buttons.length > 0) {
    payload = {
      messaging_product: 'whatsapp',
      recipient_type: 'individual',
      to: phone,
      type: 'interactive',
      interactive: {
        type: 'button',
        body: { text: msg },
        action: { buttons }
      }
    };
  } else {
    // No valid buttons after filtering
    payload = {
      messaging_product: 'whatsapp',
      recipient_type: 'individual',
      to: phone,
      type: 'text',
      text: { body: msg }
    };
  }

// ── List ───────────────────────────────────
} else if (comp === 'list' && Array.isArray(ai.list_sections) && ai.list_sections.length > 0) {
  const sections = ai.list_sections
    .map(sec => ({
      title: String(sec.title || 'Options').slice(0, 24),
      rows: (sec.rows || [])
        .filter(r => r && r.id && r.title)
        .slice(0, 10)
        .map(r => ({
          id:    String(r.id).slice(0, 200),
          title: String(r.title).slice(0, 24),
          ...(r.description ? { description: String(r.description).slice(0, 72) } : {})
        }))
    }))
    .filter(sec => sec.rows.length > 0);

  if (sections.length > 0) {
    payload = {
      messaging_product: 'whatsapp',
      recipient_type: 'individual',
      to: phone,
      type: 'interactive',
      interactive: {
        type: 'list',
        body: { text: msg },
        action: {
          button: String(ai.list_button_label || 'Select').slice(0, 20),
          sections
        }
      }
    };
  } else {
    // All sections empty after filtering
    payload = {
      messaging_product: 'whatsapp',
      recipient_type: 'individual',
      to: phone,
      type: 'text',
      text: { body: msg }
    };
  }

// ── Plain text ─────────────────────────────
} else {
  payload = {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to: phone,
    type: 'text',
    text: { body: String(ai.message).slice(0, 4096) }
  };
}

return [{ json: { phoneId, payload } }];

